import{_ as r,c as a,o as e,ae as o}from"./chunks/framework.B7Y1jjX-.js";const _=JSON.parse('{"title":"图片预加载与懒加载","description":"","frontmatter":{},"headers":[],"relativePath":"generated-notes/前端/性能优化/图片预加载与懒加载.md","filePath":"generated-notes/前端/性能优化/图片预加载与懒加载.md"}'),n={name:"generated-notes/前端/性能优化/图片预加载与懒加载.md"};function s(l,t,i,p,c,g){return e(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="图片预加载与懒加载" tabindex="-1">图片预加载与懒加载 <a class="header-anchor" href="#图片预加载与懒加载" aria-label="Permalink to &quot;图片预加载与懒加载&quot;">​</a></h1><h2 id="_1-懒加载" tabindex="-1">1 懒加载 <a class="header-anchor" href="#_1-懒加载" aria-label="Permalink to &quot;1 懒加载&quot;">​</a></h2><p><strong>懒加载也叫延迟加载，指的是在长网页中延迟加载图像，是一种很好优化网页性能的方式</strong>。用户滚动到它们之前，可视区域外的图像不会加载。这与图像预加载相反，在长网页上使用延迟加载将使网页加载更快。在某些情况下，它还可以帮助减少服务器负载。常适用图片很多，页面很长的电商网站场景中。</p><ul><li><strong>能提升用户的体验</strong>，不妨设想下，用户打开像手机淘宝长页面的时候，如果页面上所有的图片都需要加载，由于图片数目较大，等待时间很长，用户难免会心生抱怨，这就严重影响用户体验。</li><li><strong>减少无效资源的加载</strong>，这样能明显减少了服务器的压力和流量，也能够减小浏览器的负担。</li><li><strong>防止并发加载的资源过多会阻塞js的加载</strong>，影响网站的正常使用。</li></ul><p>首先将页面上的图片的 src 属性设为空字符串，而图片的真实路径则设置在data-original属性中， 当页面滚动的时候需要去监听scroll事件，在scroll事件的回调中，判断我们的懒加载的图片是否进入可视区域,如果图片在可视区内将图片的 src 属性设置为data-original 的值，这样就可以实现延迟加载。</p><h2 id="_2-预加载" tabindex="-1">2 预加载 <a class="header-anchor" href="#_2-预加载" aria-label="Permalink to &quot;2 预加载&quot;">​</a></h2><p>资源预加载是另一个性能优化技术，我们可以使用该技术来预先告知浏览器某些资源可能在将来会被使用到。<strong>预加载简单来说就是将所有所需的资源提前请求加载到本地，这样后面在需要用到时就直接从缓存取资源</strong>。</p><p>在网页全部加载之前，对一些主要内容进行加载，以提供给用户更好的体验，减少等待的时间。否则，如果一个页面的内容过于庞大，没有使用预加载技术的页面就会长时间的展现为一片空白，直到所有内容加载完毕。</p><ul><li><p>使用HTML标签 <code>&amp;lt;img src=&quot;http://pic26.nipic.com/20121213/6168183 0044449030002.jpg&quot; style=&quot;display:none&quot;/&amp;gt;</code></p></li><li><p>使用Image对象 <code>&amp;lt;script src=&quot;./myPreload.js&quot;&amp;gt;&amp;lt;/script&amp;gt;</code></p></li></ul><h3 id="特殊情况" tabindex="-1">特殊情况 <a class="header-anchor" href="#特殊情况" aria-label="Permalink to &quot;特殊情况&quot;">​</a></h3><p>&gt; <strong>场景</strong>：预加载图片 A（<code>new Image().src = A</code>），但正式请求 A 已发出。此时预加载还有效吗？</p><p><strong>答案：有效，且能提升性能</strong>。</p><p><strong>原理</strong>：</p><ul><li>浏览器对同一 URL 的资源有<strong>全局缓存机制</strong>（包括内存缓存、磁盘缓存）。</li><li>预加载时，图片开始下载并存入缓存。</li><li>当正式 <code>&amp;lt;img src=&quot;A&quot;&amp;gt;</code> 请求发出时： <ul><li>若预加载已完成 → 直接从缓存读取（毫秒级）；</li><li>若预加载正在进行 → 浏览器会<strong>复用同一个 TCP 连接和下载流</strong>（Chrome 等现代浏览器支持）；</li><li>即使正式请求先发，预加载后发，只要 URL 相同，最终都会共享缓存。</li></ul></li></ul><p>&gt; <strong>例外</strong>：若预加载和正式请求的 <strong>headers 不同</strong>（如 CORS、Referer），可能被视为不同资源，无法共享。</p><h2 id="三、懒加载和预加载的对比" tabindex="-1">三、懒加载和预加载的对比 <a class="header-anchor" href="#三、懒加载和预加载的对比" aria-label="Permalink to &quot;三、懒加载和预加载的对比&quot;">​</a></h2><p>两者都是提高页面性能有效的办法，<strong>两者主要区别是一个是提前加载，一个是迟缓甚至不加载。懒加载对服务器前端有一定的缓解压力作用，预加载则会增加服务器前端压力</strong>。</p><p>作者：浪里行舟<br> 链接：<a href="https://juejin.cn/post/6844903614138286094" target="_blank" rel="noreferrer">https://juejin.cn/post/6844903614138286094</a><br> 来源：稀土掘金<br> 著作权归作者所有。商业转载请联系作者获得授权，非商业转载请注明出处。</p>',18)])])}const h=r(n,[["render",s]]);export{_ as __pageData,h as default};
